import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"九宝琉璃塔","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/2.社交类/九宝琉璃塔.md","filePath":"4.资源分区/1.血统与训练/2.社交类/九宝琉璃塔.md"}'),s={name:"4.资源分区/1.血统与训练/2.社交类/九宝琉璃塔.md"};function o(d,b,_,l,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"九宝琉璃塔",tabindex:"-1"},[p("九宝琉璃塔 "),r("a",{class:"header-anchor",href:"#九宝琉璃塔","aria-label":'Permalink to "九宝琉璃塔"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"汹涌疾风024")])])],-1),n('<h1 id="九宝琉璃塔-1" tabindex="-1">九宝琉璃塔 <a class="header-anchor" href="#九宝琉璃塔-1" aria-label="Permalink to &quot;九宝琉璃塔&quot;">​</a></h1><p>九宝琉璃塔</p><p>前身为七宝琉璃塔，斗罗大陆中最强辅助武魂，质如水晶，九层九色，形如兰殿桂宫。<br> 立于手中不过三寸，然行于天地则层峦耸翠，上出重霄；飞阁流丹，下临无地。</p><p>因为武魂仅先天觉醒决定，主神将其收录为血统。</p><p>D级<br> 在强化这一级别血统后，购买者的身体上会浮现象征琉璃塔的魂印。<br> 能量池：魂力<br> 魂力是一个通用能量池，其关键属性为【智力+操控】<br> 魂力的恢复方式：<br> 1、短休息时，进行一个关键属性检定，恢复成功数点能量<br> 2、进行长休息以后，能量池恢复满值。<br> 无论如何，一日内恢复的能量值不能超过上限的三倍。<br> 魂力的基本用法：进行智力/操控检定时，以自由动作支付1点魂力在这一检定上获得1点能量加值。</p><p>特性：【武魂展现】<br> 【武魂展现】：以一个移动动作召唤出武魂，此时你的手上会浮现出一座玲珑塔，它会占据手持位。每展现一轮武魂，你就会消耗一点魂力。武魂展现会持续一个场景。<br> 当处于武魂展现状态时，你可以使用九宝玲珑塔的魂技。初始状态下，九宝琉璃塔只有一种魂技。<br> 九宝琉璃塔的内在支线等级与人物掌握的魂技数量有关，当人物掌握了第3/5/7/9魂技时，其内在等级提升至C/B/A/S级。<br> 当九宝琉璃塔达到C级时，人物处于武魂展现状态下免疫C级别措手不及。使用指定友方单位为目标的魂技时，射程提升操控属性米，并且可以额外指定一个友方单位。<br> 当九宝琉璃塔达到B级时，人物处于武魂展现状态下免疫B级别措手不及。使用指定友方单位为目标的魂技时，射程再提升操控属性米，可以再额外指定操控附加成功个友方单位。 当九宝琉璃塔到达A级时，人物处于武魂展现状态下免疫A级别措手不及、定身、昏迷状态。使用指定友方单位为目标的魂技时，射程提升至敏感范围，可以指定范围内的所有友方单位为目标。</p><p>【宝物探知】：当你处于武魂展现状态时，你可以一个花招动作选择视觉范围内的一个物体，通过【感知+洞察+搜索】检定，以对抗该物体的支线等级*6，若成功则可以知道该物体的大致价值为多少。这是一个D级别、命运来源的解析效果。需要注意的是，这一难度等级会根据物体的当前状况（伪装状态、神物自晦等）而有所浮动。</p><p>魂技<br> 除第一魂技为购买D级血统时赠送外，其他魂技需要按次序花费支线与分数进行购买。每具有一项魂技，你的九宝琉璃塔上便会多出一道金色的魂环。（当然如果有需要你可以自行定义颜色）</p><p>【一曰：力】<br> 动作：花招<br> 消耗：2点魂力<br> 射程：15米<br> 目标：单个友方单位<br> 持续：三轮<br> 使用时需要角色念出：九宝转出有琉璃。九宝有名，一曰：力<br> 效果：受影响单位在力量检定上获得对方传奇力量*2点增强加值。</p><p>【二曰：速】<br> 价格：D+600<br> 动作：花招<br> 消耗：2点魂力<br> 射程：15米<br> 目标：单个友方单位<br> 持续：三轮<br> 使用时需要角色念出：九宝转出有琉璃。九宝有名，二曰：速<br> 效果：受影响单位在持续时间内速度提升10米、先攻提升传奇敏捷*2点、敏捷检定获得传奇敏捷*1点速度加值。<br> 额外支付D+500：受影响单位的速度再提升传奇敏捷*5米、敏捷检定再获得传奇敏捷*1点速度加值。</p><p>【三曰：魂】<br> 价格：D+600<br> 动作：花招<br> 消耗：2点魂力<br> 射程：15米<br> 目标：单个友方单位<br> 持续：三轮<br> 使用时需要角色念出：九宝转出有琉璃。九宝有名，三曰：魂。紧接着，九宝琉璃塔将发出三声脆响，将魂光降落在友方身上。<br> 效果：受影响单位在持续时间内，每轮首次消耗的心智为关键属性之一的通用能量减少3点（至少为1）。</p><p>【四曰：御】<br> 价格：C+1200<br> 动作：移动<br> 消耗：6点魂力<br> 射程：15米<br> 目标：单个友方单位<br> 持续：三轮<br> 使用时需要角色念出：九宝转出有琉璃。九宝有名，四曰：御。之后九宝琉璃塔身光芒大放，防御之光会如同坚盾般覆盖队友全身。<br> 效果：受影响单位在持续时间内获得等于使用者的操控属性点的力场防御以及基于力场防御的【坚韧】效果。</p><p>【五曰：攻】<br> 价格：C+1200<br> 动作：移动<br> 消耗：6点魂力<br> 射程：15米<br> 目标：单个友方单位<br> 持续：三轮<br> 使用时需要角色念出：九宝转出有琉璃。九宝有名，五曰：攻。接着九宝琉璃塔的第五层浮雕上的剑气将会倏然冲入队友体内。<br> 效果：受影响单位在持续时间内，攻击上获得等于使用者的操控属性点的表现加值，并且攻击上的加骰等级提升2级，至多为8加骰。</p><p>【六曰：增】<br> 价格：B+2400<br> 动作：标准<br> 消耗：10点魂力<br> 射程：45米<br> 目标：单个友方单位<br> 持续：三轮<br> 使用时需要角色念出：九宝转出有琉璃。九宝有名，六曰：增。此时琉璃塔上将会有道道七色流光游至队友周围。<br> 效果：<br> 受影响单位的最高属性的检定获得使用者传奇操控*2点机运加值，若有多个属性，则受影响单位在获得增益时选择其中一个属性获得这一加值。<br> 若受影响单位同时受到了琉璃塔前五个魂技的增益，则根据对应的魂技获得额外的增益效果：<br> 一曰：力-进行的攻击检定获得毁灭特性，若已经具有毁灭，则提升至湮灭。<br> 二曰：速-每轮一次，其在进行招架行为时，视为移出了攻击范围。<br> 三曰：魂-减少的能量消耗再提升3点。<br> 四曰：御-坚韧提升至超级坚韧<br> 五曰：攻-攻击获得超级贯穿特性</p><p>【七曰：九宝真身】<br> 价格：B+2400<br> 动作：移动<br> 消耗：10点魂力<br> 射程：无<br> 目标：自身<br> 持续：一场景或自身主动进行移动<br> 使用时需要角色念出：九宝转出有琉璃。九宝有名，七曰：九宝真身。琉璃塔的虚影会增大并覆盖你的周围，放射出道道璀璨光芒。<br> 效果：<br> 自身在效果持续时间内，释放的所有九宝琉璃塔的魂技能量消耗减半，但至少为1。先结算减少消耗再结算减半。<br> 自身在效果持续时间内，视为全防御状态。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',17)])])}const m=e(s,[["render",o]]);export{f as __pageData,m as default};
